# BFS: Shortest path in unweighted graph
from collections import deque, defaultdict

def bfs_shortest_path(graph, start, target):
    # graph: adjacency list (defaultdict(list))
    # ABAP equivalent: HASHED TABLE with STANDARD TABLE values
    visited = {start}
    queue = deque([(start, [start])])  # (node, path)
    # ABAP: queue as STANDARD TABLE, DELETE INDEX 1 for dequeue

    while queue:
        node, path = queue.popleft()  # dequeue
        if node == target:
            return path
        for neighbor in graph[node]:
            if neighbor not in visited:
                visited.add(neighbor)
                queue.append((neighbor, path + [neighbor]))
    return None

# DFS: Detect cycle in directed graph
def has_cycle(graph):
    WHITE, GRAY, BLACK = 0, 1, 2  # unvisited, in-stack, done
    color = {node: WHITE for node in graph}

    def dfs(node):
        if color[node] == GRAY:
            return True  # back edge = cycle
        if color[node] == BLACK:
            return False
        color[node] = GRAY  # on recursion stack (AT NEW)
        for neighbor in graph[node]:
            if dfs(neighbor):
                return True
        color[node] = BLACK  # done (ENDAT)
        return False

    for node in graph:
        if color[node] == WHITE:
            if dfs(node):
                return True
    return False

# Dijkstra: Shortest path with weighted edges
import heapq

def dijkstra(graph, start):
    # graph: defaultdict(list) of (neighbor, weight)
    distances = {node: float('inf') for node in graph}
    distances[start] = 0
    pq = [(0, start)]  # priority queue (heapq)
    # ABAP: SORTED TABLE by distance, READ INDEX 1

    while pq:
        dist, node = heapq.heappop(pq)
        if dist > distances[node]:
            continue
        for neighbor, weight in graph[node]:
            new_dist = dist + weight
            if new_dist < distances[neighbor]:
                distances[neighbor] = new_dist
                heapq.heappush(pq, (new_dist, neighbor))
    return distances

