# 0/1 Knapsack (bottom-up)
def knapsack(weights, values, capacity):
    n = len(weights)
    dp = [[0] * (capacity + 1) for _ in range(n + 1)]
    # ABAP: internal table with capacity + 1 columns

    for i in range(1, n + 1):  # LOOP AT items
        for w in range(capacity + 1):  # LOOP AT capacities
            if weights[i-1] <= w:
                dp[i][w] = max(
                    dp[i-1][w],  # skip item
                    dp[i-1][w - weights[i-1]] + values[i-1]  # take item
                )
            else:
                dp[i][w] = dp[i-1][w]
    return dp[n][capacity]

# LCS (top-down with memoization)
def lcs(text1, text2):
    from functools import lru_cache

    @lru_cache(None)
    def dp(i, j):
        if i == len(text1) or j == len(text2):
            return 0
        if text1[i] == text2[j]:
            return 1 + dp(i + 1, j + 1)
        return max(dp(i + 1, j), dp(i, j + 1))

    return dp(0, 0)

