# O(1) - HASHED TABLE READ → dict.get(key)
# O(log n) - BINARY SEARCH → bisect.bisect_left(arr, x)
# O(n) - LOOP AT → for x in arr
# O(n log n) - SORT → sorted(arr) / arr.sort()
# O(n²) - nested LOOP AT → for a in arr: for b in arr:

def constant_lookup(d, key):
    return d.get(key)  # O(1) READ TABLE WITH TABLE KEY

import bisect
def binary_search(arr, x):
    idx = bisect.bisect_left(arr, x)
    return idx if idx < len(arr) and arr[idx] == x else -1  # O(log n)

def linear_search(arr, target):
    for i, val in enumerate(arr):
        if val == target:
            return i
    return -1  # O(n)
